const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = input[idx++];
  const M = input[idx++];
  const X = input[idx++];
  const g = Array.from({length: N + 1}, () => []);
  for (let i = 0; i < M; i++) {
    const u = input[idx++];
    const v = input[idx++];
    g[u].push(v);
    g[v].push(u);
  }
  for (let i = 1; i <= N; i++) g[i].sort((a, b) => a - b);
  const visited = new Array(N + 1).fill(false);
  const queue = [];
  const order = [];
  queue.push(X);
  visited[X] = true;
  while (queue.length) {
    const cur = queue.shift();
    order.push(cur);
    for (const nb of g[cur]) {
      if (!visited[nb]) {
        visited[nb] = true;
        queue.push(nb);
      }
    }
  }
  outputs.push(order.join(' '));
}
